try:
    import arabic_reshaper
    from bidi.algorithm import get_display
except Exception:
    arabic_reshaper = None
    get_display = None


def ar_text(text):
    text = "" if text is None else str(text)
    if arabic_reshaper and get_display:
        try:
            return get_display(arabic_reshaper.reshape(text))
        except Exception:
            return text
    return text


def _safe_filename(name):
    name = normalize_name(name)
    name = re.sub(r"[^A-Za-z0-9_.\-\u0600-\u06FF]+", "_", name).strip("_")
    return name or "file"


def ensure_generated_dir():
    os.makedirs(GENERATED_DIR, exist_ok=True)


def load_settings():
    default = {"auto_images": True}
    if not os.path.exists(SETTINGS_FILE):
        return default
    try:
        with open(SETTINGS_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
        default.update(data if isinstance(data, dict) else {})
    except Exception:
        pass
    return default


def save_settings(settings):
    with open(SETTINGS_FILE, "w", encoding="utf-8") as f:
        json.dump(settings, f, ensure_ascii=False, indent=2)


def admin_id_set():
    raw = os.getenv("ADMIN_IDS") or os.getenv("ADMINS") or ""
    ids = set()
    for part in raw.replace(";", ",").split(","):
        part = part.strip()
        if not part:
            continue
        try:
            ids.add(int(part))
        except Exception:
            pass
    return ids


def is_admin_user(update):
    ids = admin_id_set()
    if not ids:
        # إذا ما ضبطت ADMIN_IDS في Railway نخلي البوت يشتغل عشان ما ينقفل عليك.
        return True
    user = getattr(update, "effective_user", None)
    return bool(user and user.id in ids)


def admin_only(func):
    async def wrapper(update: Update, context: ContextTypes.DEFAULT_TYPE):
        if not is_admin_user(update):
            await update.message.reply_text("هذا الأمر للمشرفين فقط 🔒")
            return
        return await func(update, context)
    return wrapper


