    draw_text(draw, (540, 174), f"ترتيب المجموعات | {page_no}/{total_pages}", get_font(30), fill="#FBBF24")
    # RTL: أعلى يمين ثم أعلى يسار، أسفل يمين ثم أسفل يسار
