MENU_TRIGGER_WORDS = {"القائمة", "ابدا", "اطل", "زبد", "المصيف", "ستارت"}


def get_existing_days(start_day=1, end_day=39):
    days = []
    try:
        for filename in os.listdir("."):
            m = re.match(r"fantasy_day_(\d+)\.xlsx$", filename)
            if not m:
                continue
            day = int(m.group(1))
            if int(start_day) <= day <= int(end_day):
                days.append(day)
    except Exception:
        pass
    return sorted(days)


